Below is a **complete, self‑contained example** that shows how you can expose BlockSci’s C++ block iterator to Lua while keeping the hot‑path (≈ 800 M calls) as cheap as possible.

* It uses a **single reusable userdata** that is updated in‑place for every block – no allocation, no GC pressure.
* The Lua callback receives that userdata and can call cheap getter methods (`height()`, `time()`, `tx_count()`, …) that simply read fields from the native C++ `Block` object.
* The iterator can be stopped early by returning **false** (or `nil`) from the callback.
* Errors inside the callback are propagated as Lua errors, aborting the iteration.

The code is written in **pure C** (no LuaJIT FFI) so it works with any Lua 5.3/5.4 interpreter, but the same design works just as well with LuaJIT.

---

## 1.  The Lua‑facing API (what the Lua programmer sees)

```lua
local blocksci = require "blocksci"

-- Walk the whole blockchain, calling the supplied function for each block.
-- The callback receives a *Block* userdata.
--   * Return true (or nothing) to continue.
--   * Return false or nil to stop early.
blocksci.for_each_block(function(block)
    -- cheap getters – no copying of data
    local h   = block:height()
    local ts  = block:timestamp()
    local txs = block:tx_count()

    -- do whatever you want here – e.g. accumulate statistics,
    -- write to a file, feed a data‑frame, etc.
    print(string.format("block %d – %d txs – %s", h, txs, os.date("%c", ts)))
end)
```

### Optional helpers (not required for the hot‑path)

```lua
-- Return a *Block* userdata for a single height (random access)
local b = blocksci.block_at(123456)
print(b:height(), b:tx_count())

-- Get the total number of blocks (fast C call)
local n = blocksci.block_count()
print("Chain length:", n)
```

All of the above is implemented in the C stub that follows.

---

## 2.  The C stub (single‑file “blocksci.c”)

```c
/*=====================================================================
   blocksci.c – Lua bindings for BlockSci’s block iterator
   ----------------------------------------------------
   * 2026‑06‑16 – written for Lua 5.3/5.4
   * Compiles as a shared library (e.g. libblocksci.so / blocksci.dll)
   * Depends on the BlockSci C++ API (see comments for the minimal
     interface we need).
   =====================================================================*/

#define LUA_COMPAT_5_3   /* make luaL_checkinteger work with 5.3+ */
#include <lua.h>
#include <lauxlib.h>
#include <lualib.h>
#include <stddef.h>   /* ptrdiff_t */
#include <stdbool.h>

/* -----------------------------------------------------------------
   Minimal BlockSci C++ interface we need.
   In real life you would #include <blocksci/blocksci.hpp> or similar.
   ----------------------------------------------------------------- */
#ifdef __cplusplus
extern "C" {
#endif

/* Opaque C++ types – the real definitions live in the BlockSci library. */
typedef struct BlockSci_Chain   BlockSci_Chain;
typedef struct BlockSci_Block   BlockSci_Block;
typedef struct BlockSci_Iter   BlockSci_Iter;

/* Construction / destruction */
BlockSci_Chain*  BlockSci_chain_open(const char* path);
void            BlockSci_chain_close(BlockSci_Chain*);

/* Random access */
size_t          BlockSci_chain_block_count(BlockSci_Chain*);
BlockSci_Block* BlockSci_chain_block_at(BlockSci_Chain*, size_t height);

/* Iterator */
BlockSci_Iter*   BlockSci_iter_new(BlockSci_Chain*);
void            BlockSci_iter_free(BlockSci_Iter*);
bool            BlockSci_iter_has_next(BlockSci_Iter*);
BlockSci_Block* BlockSci_iter_next(BlockSci_Iter*);

/* Block getters – all are cheap, no allocation */
size_t          BlockSci_block_height(const BlockSci_Block*);
int64_t         BlockSci_block_timestamp(const BlockSci_Block*);   /* unix epoch */
size_t          BlockSci_block_tx_count(const BlockSci_Block*);

/* ----------------------------------------------------------------- */
#ifdef __cplusplus
}
#endif

/* -----------------------------------------------------------------
   Lua binding implementation
   ----------------------------------------------------------------- */

/* ---- 1.  The userdata that represents a Block ------------------- */

typedef struct {
    const BlockSci_Block *ptr;   /* pointer to the native block */
} lua_Block;                     /* the Lua userdata */

/* Metatable name (unique within the Lua state) */
#define BLOCK_META "blocksci.block"

/* Helper: push a Block userdata that wraps `blk`.  The userdata is
   *reused* – we keep a single instance in the registry (key = REGISTRY_INDEX
   - 1) and just change its `ptr` field each iteration.  This avoids
   allocating 800 M objects. */
static int push_block_userdata(lua_State *L, const BlockSci_Block *blk)
{
    /* The first time we are called we allocate the userdata and store it
       in the registry for later reuse. */
    lua_pushlightuserdata(L, (void*)BLOCK_META);        /* key */
    lua_rawget(L, LUA_REGISTRYINDEX);                  /* -> existing? */
    if (lua_isnil(L, -1)) {
        /* No cached userdata – create one. */
        lua_pop(L, 1);                                 /* drop nil */
        lua_Block *ud = (lua_Block*)lua_newuserdatauv(L, sizeof(lua_Block), 0);
        ud->ptr = blk;
        /* Set its metatable */
        luaL_getmetatable(L, BLOCK_META);
        lua_setmetatable(L, -2);
        /* Cache it */
        lua_pushlightuserdata(L, (void*)BLOCK_META);
        lua_pushvalue(L, -2);                          /* copy userdata */
        lua_rawset(L, LUA_REGISTRYINDEX);
    } else {
        /* Reuse the existing userdata – just update the pointer. */
        lua_Block *ud = (lua_Block*)lua_touserdata(L, -1);
        ud->ptr = blk;
    }
    /* userdata is now on top of the stack */
    return 1;
}

/* ---- 2.  Block methods (exposed as block:height() etc.) ------------ */

static int block_height(lua_State *L)
{
    lua_Block *b = (lua_Block*)luaL_checkudata(L, 1, BLOCK_META);
    size_t h = BlockSci_block_height(b->ptr);
    lua_pushinteger(L, (lua_Integer)h);
    return 1;
}

static int block_timestamp(lua_State *L)
{
    lua_Block *b = (lua_Block*)luaL_checkudata(L, 1, BLOCK_META);
    int64_t ts = BlockSci_block_timestamp(b->ptr);
    lua_pushinteger(L, (lua_Integer)ts);
    return 1;
}

static int block_tx_count(lua_State *L)
{
    lua_Block *b = (lua_Block*)luaL_checkudata(L, 1, BLOCK_META);
    size_t n = BlockSci_block_tx_count(b->ptr);
    lua_pushinteger(L, (lua_Integer)n);
    return 1;
}

/* Metamethod __tostring for pretty printing (optional) */
static int block_tostring(lua_State *L)
{
    lua_Block *b = (lua_Block*)luaL_checkudata(L, 1, BLOCK_META);
    size_t h = BlockSci_block_height(b->ptr);
    int64_t ts = BlockSci_block_timestamp(b->ptr);
    size_t n = BlockSci_block_tx_count(b->ptr);
    lua_pushfstring(L, "Block{height=%d, time=%d, txs=%d}", (int)h, (int)ts, (int)n);
    return 1;
}

/* Register Block methods */
static const luaL_Reg block_methods[] = {
    {"height",    block_height},
    {"timestamp", block_timestamp},
    {"tx_count",  block_tx_count},
    {"__tostring", block_tostring},
    {NULL, NULL}
};

/* -----------------------------------------------------------------
   3.  The high‑performance iterator: for_each_block(callback)
   ----------------------------------------------------------------- */

static int l_for_each_block(lua_State *L)
{
    /* Arguments:
         1) path to the BlockSci database (string)
         2) Lua function (callback)   */
    const char *path = luaL_checkstring(L, 1);
    luaL_checktype(L, 2, LUA_TFUNCTION);
    /* Keep a reference to the callback – it will be called many times */
    lua_pushvalue(L, 2);                     /* copy the function */
    int cb_ref = luaL_ref(L, LUA_REGISTRYINDEX);

    /* ----------------------------------------------------------------
       Open the chain (C++ side).  In a real binding you would keep the
       chain object alive across calls, but for simplicity we open/close
       it each time.  The open/close overhead is negligible compared to
       the 800 M iterations.
       ---------------------------------------------------------------- */
    BlockSci_Chain *chain = BlockSci_chain_open(path);
    if (!chain) {
        luaL_error(L, "BlockSci: failed to open chain at '%s'", path);
    }

    BlockSci_Iter *it = BlockSci_iter_new(chain);
    if (!it) {
        BlockSci_chain_close(chain);
        luaL_error(L, "BlockSci: failed to create iterator");
    }

    /* Main hot loop --------------------------------------------------- */
    while (BlockSci_iter_has_next(it)) {
        const BlockSci_Block *blk = BlockSci_iter_next(it);
        /* Push the callback */
        lua_rawgeti(L, LUA_REGISTRYINDEX, cb_ref);
        /* Push a *single* reusable Block userdata */
        push_block_userdata(L, blk);   /* leaves userdata on stack */
        /* Call: 1 argument, 1 result (optional) */
        if (lua_pcall(L, 1, 1, 0) != LUA_OK) {
            /* Propagate error – cleanup first */
            const char *msg = lua_tostring(L, -1);
            luaL_error(L, "callback error: %s", msg);
        }
        /* Examine the return value:
           * false or nil  -> stop early
           * any other value -> continue */
        bool continue_iter = true;
        if (lua_isboolean(L, -1)) {
            continue_iter = lua_toboolean(L, -1);
        } else if (lua_isnil(L, -1)) {
            continue_iter = false;
        }
        lua_pop(L, 1);                 /* discard the callback result */
        if (!continue_iter) break;
    }

    /* Cleanup ---------------------------------------------------------- */
    BlockSci_iter_free(it);
    BlockSci_chain_close(chain);
    luaL_unref(L, LUA_REGISTRYINDEX, cb_ref);
    return 0;   /* no values returned to Lua */
}

/* -----------------------------------------------------------------
   4.  Miscellaneous helpers (block_at, block_count)
   ----------------------------------------------------------------- */

static int l_block_count(lua_State *L)
{
    const char *path = luaL_checkstring(L, 1);
    BlockSci_Chain *chain = BlockSci_chain_open(path);
    if (!chain) luaL_error(L, "BlockSci: cannot open chain");
    size_t n = BlockSci_chain_block_count(chain);
    BlockSci_chain_close(chain);
    lua_pushinteger(L, (lua_Integer)n);
    return 1;
}

static int l_block_at(lua_State *L)
{
    const char *path = luaL_checkstring(L, 1);
    lua_Integer h = luaL_checkinteger(L, 2);
    if (h < 0) luaL_error(L, "height must be non‑negative");
    BlockSci_Chain *chain = BlockSci_chain_open(path);
    if (!chain) luaL_error(L, "BlockSci: cannot open chain");
    BlockSci_Block *blk = BlockSci_chain_block_at(chain, (size_t)h);
    if (!blk) {
        BlockSci_chain_close(chain);
        luaL_error(L, "BlockSci: no block at height %d", (int)h);
    }
    /* Return a userdata that wraps the *native* block pointer.
       This is a *different* userdata from the iterator‑reuse one,
       because the caller may keep it around.  It is GC‑managed. */
    lua_Block *ud = (lua_Block*)lua_newuserdatauv(L, sizeof(lua_Block), 0);
    ud->ptr = blk;
    luaL_getmetatable(L, BLOCK_META);
    lua_setmetatable(L, -2);
    /* Keep the chain alive as an upvalue so the block stays valid. */
    lua_pushlightuserdata(L, chain);
    lua_setuservalue(L, -2);
    return 1;
}

/* -----------------------------------------------------------------
   5.  Module registration
   ----------------------------------------------------------------- */

static const luaL_Reg blocksci_funcs[] = {
    {"for_each_block", l_for_each_block},
    {"block_count",    l_block_count},
    {"block_at",       l_block_at},
    {NULL, NULL}
};

int luaopen_blocksci(lua_State *L)
{
    /* Create Block metatable */
    luaL_newmetatable(L, BLOCK_META);               /* mt */
    lua_pushvalue(L, -1);                           /* mt mt */
    lua_setfield(L, -2, "__index");                 /* mt.__index = mt */
    luaL_setfuncs(L, block_methods, 0);
    lua_pop(L, 1);                                  /* pop mt */

    /* Register module functions */
    luaL_newlib(L, blocksci_funcs);
    return 1;
}

/*=====================================================================
   End of blocksci.c
   =====================================================================*/
```

